Window.Resources.Aspect:
@handle Reactor;
@handle Pipeline;
@when $PageMotion.Visibility
{
    @if value == Visible
    {
        @run $ReactorReplay as Reactor;
    }
    @if value == Collapsed
    {
        @cancel Reactor;
    }
}
@when $ReplayMotionButton.IsPressed
{
    @run $ReactorReplay as Reactor;
}
@when $PagePipeline.Visibility
{
    @if value == Visible
    {
        @run $PipelineReplay as Pipeline;
    }
    @if value == Collapsed
    {
        @cancel Pipeline;
    }
}
@when $RunPipelineButton.IsPressed
{
    @run $PipelineReplay as Pipeline;
}

@when Visibility
{
    @if Visibility == Visible
    {
        @parallel
        {
            @animate with Tween(360ms, EaseOut)
            {
                @from
                {
                    Opacity = 0.25;
                }
                @to
                {
                    Opacity = 1;
                }
            }
            @animate with Spring(460, 38)
            {
                @from
                {
                    TranslateY = 18;
                }
                @to
                {
                    TranslateY = 0;
                }
            }
        }
    }
}

@default
{
    FontFamily = "Segoe UI Variable Text";
    FontSize = 14;
    Foreground = $PaperBrush;
}

@default
{
    FontFamily = "Cascadia Mono SemiBold";
    FontSize = 12;
    Background = $TransparentBrush;
    Foreground = $SlateBrush;
    BorderBrush = $TransparentBrush;
    BorderThickness = "0";
    Padding = "18,10,12,10";
}
@when IsChecked
{
    Background = $CyanWashBrush;
    Foreground = $PaperBrush;
    BorderBrush = $LimeBrush;
}
@when IsMouseOver
{
    @if IsMouseOver == true
    {
        @parallel
        {
            @animate with $NavHoverIn
            {
                @from
                {
                    Background = current;
                    $self.parts.$PART_HoverLine.ScaleX = current;
                }
                @to
                {
                    Background = $CyanWashBrush;
                    $self.parts.$PART_HoverLine.ScaleX = 1;
                }
            }
            @animate with $NavTextHover
            {
                @from
                {
                    Foreground = current;
                    $self.parts.$PART_HoverText.Opacity = current;
                }
                @to
                {
                    Foreground = $PaperBrush;
                    $self.parts.$PART_HoverText.Opacity = 1;
                }
            }
        }
    }
    @if IsMouseOver == false
    {
        @parallel
        {
            @animate with $NavHoverOut
            {
                @from
                {
                    Background = current;
                    $self.parts.$PART_HoverLine.ScaleX = current;
                }
                @to
                {
                    Background = $TransparentBrush;
                    $self.parts.$PART_HoverLine.ScaleX = 0;
                }
            }
            @animate with $NavTextHover
            {
                @from
                {
                    Foreground = current;
                    $self.parts.$PART_HoverText.Opacity = current;
                }
                @to
                {
                    Foreground = $SlateBrush;
                    $self.parts.$PART_HoverText.Opacity = 0;
                }
            }
        }
    }
}
@template
{












}

@default
{
    FontFamily = "Cascadia Mono SemiBold";
    FontSize = 12;
    Background = $TransparentBrush;
    Foreground = $PaperBrush;
    BorderBrush = $LineStrongBrush;
    BorderThickness = "1";
    Padding = "18,11,18,11";
}
@when IsMouseOver
{
    Background = $CyanWashBrush;
    Foreground = $CyanBrush;
    BorderBrush = $CyanBrush;
}

@default
{
    FontFamily = "Cascadia Mono SemiBold";
    FontSize = 12;
    Background = $LimeBrush;
    Foreground = $InkBrush;
    BorderBrush = $LimeBrush;
    BorderThickness = "1";
    Padding = "20,12,20,12";
}
@when IsMouseOver
{
    Background = $CyanBrush;
    BorderBrush = $CyanBrush;
}

TextBlock.Text:
public partial class MainWindow : Window
{
  private void OnLaunch(
    UiElementId sender,
    RoutedEventArgs args)
  {
    Launch.Motion()
      .Scale.To(
        1.08f,
        Motion.Spring<float>());
  }
}
